#!/usr/bin/env python3"""Real screenshot capture for NIKTO.Uses ``mss`` (cross-platform) or ``pyautogui`` to capture the screenand save as PNG.  Raises ``RuntimeError`` if no capture library isavailable."""import osimport timefrom datetime import datetimefrom pathlib import Pathfrom typing import Optionaldef capture_screenshot(output_path: Optional[str] = None) -> str:    """Capture the entire screen and save to *output_path* (default: ``screenshots/capture_<timestamp>.png``).    Returns the path to the saved file.    Raises ``RuntimeError`` if neither ``mss`` nor ``pyautogui`` is    installed.    """    if output_path is None:        out_dir = Path(__file__).resolve().parent        out_dir.mkdir(parents=True, exist_ok=True)        ts = datetime.now().strftime("%Y%m%d_%H%M%S")        output_path = str(out_dir / f"capture_{ts}.png")    # Try mss first (faster, no dependency on pyautogui)    try:        import mss  # type: ignore[import-untyped]        with mss.mss() as sct:            monitor = sct.monitors[0]            sct.shot(mon=monitor, output=output_path)        return output_path    except ImportError:        pass    # Fallback: pyautogui    try:        import pyautogui  # type: ignore[import-untyped]        img = pyautogui.screenshot()        img.save(output_path)        return output_path    except ImportError:        pass    raise RuntimeError(        "No screen-capture library available. Install mss or pyautogui: "        "pip install mss  # or  pip install pyautogui"    )def capture_window(title: str, output_path: Optional[str] = None) -> str:    """Capture a specific window by *title* (basic heuristic using pyautogui).    Falls back to full-screen capture if window detection is unavailable.    """    try:        import pygetwindow as gw  # type: ignore[import-untyped]        windows = gw.getWindowsWithTitle(title)        if windows:            win = windows[0]            if win.isMinimized:                win.restore()            time.sleep(0.3)            win.activate()            time.sleep(0.3)    except ImportError:        pass    return capture_screenshot(output_path)if __name__ == "__main__":    path = capture_screenshot()    print(f"Screenshot saved: {path}")